 12→function NumberInput({ label, value, onChange, suffix = 'mm', step = 1, readOnly = false }) {
 13→  return (
 14→    <label className={styles.field}>
 15→      <span className={styles.fieldLabel}>{label}</span>
 16→      <div className={styles.fieldInput}>
 17→        <input
 18→          type="number"
 19→          value={Math.round(value)}
 20→          step={step}
 21→          readOnly={readOnly}
 22→          onChange={(e) => {
 23→            const v = parseFloat(e.target.value);
 24→            if (!isNaN(v)) onChange(v);
 25→          }}
 26→          onBlur={(e) => {
 27→            if (readOnly) return;
 28→            const v = parseFloat(e.target.value);
 29→            if (!isNaN(v)) {
 30→              const clamped = clampDimension(v);
 31→              if (clamped !== v) onChange(clamped);
 32→            }
 33→          }}
 34→          className={styles.numberInput}
 35→        />
 36→        {suffix && <span className={styles.suffix}>{suffix}</span>}
 37→      </div>
 38→    </label>
 39→  );
 40→}
