 1→import { useEffect, useRef } from 'react';
 2→import styles from './Modal.module.css';
 3→
 4→export default function Modal({ title, onClose, children }) {
 5→  const overlayRef = useRef(null);
 6→
 7→  useEffect(() => {
 8→    const handleKey = (e) => {
 9→      if (e.key === 'Escape') onClose();
10→    };
11→    window.addEventListener('keydown', handleKey);
12→    return () => window.removeEventListener('keydown', handleKey);
13→  }, [onClose]);
14→
15→  const handleOverlayClick = (e) => {
16→    if (e.target === overlayRef.current) onClose();
17→  };
18→
19→  return (
20→    <div ref={overlayRef} onClick={handleOverlayClick} className={styles.overlay}>
21→      <div className={styles.dialog}>
22→        <div className={styles.header}>
23→          <h3 className={styles.headerTitle}>{title}</h3>
24→          <button type="button" className={styles.closeBtn} onClick={onClose} aria-label="Close">
25→            <svg viewBox="0 0 20 20" aria-hidden="true" className={styles.closeIcon}>
26→              <path d="M6 6l8 8M14 6l-8 8" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
27→            </svg>
28→          </button>
29→        </div>
30→        <div className={styles.body}>
31→          {children}
32→        </div>
33→      </div>
34→    </div>
35→  );
36→}
