  1→import { projectPartToView } from '../../domain/viewProjection';
  2→import { projectDimensionPoint } from '../../renderers/DimensionRenderer';
  3→import { createDimensionFigure, hitTestDimensionFigure } from '@/annotations/dimensions';
  4→import { snapPoint } from '../snap';
  5→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  6→
  7→export function createSketchSelectHandler({ dispatch, editorDispatch, project, activeView, viewport, snapEnabled }) {
  8→  function hitTestDimensions(modelPos) {
  9→    const tolerance = 8 / viewport.zoom;
 10→    const dims = project.parts.filter((p) => p.type === 'dimension');
 11→
 12→    for (let i = dims.length - 1; i >= 0; i--) {
 13→      const dim = dims[i];
 14→      const start2D = projectDimensionPoint(dim.startPoint, activeView);
 15→      const end2D = projectDimensionPoint(dim.endPoint, activeView);
 16→
 17→      const figure = createDimensionFigure({
 18→        id: dim.id,
 19→        startPoint: start2D,
 20→        endPoint: end2D,
 21→        mode: 'aligned',
 22→        offset: dim.offset || 200,
 23→        source: 'manual',
 24→      });
 25→
 26→      if (figure && hitTestDimensionFigure(modelPos, figure, tolerance)) {
 27→        return { id: dim.id, type: 'part' };
 28→      }
 29→    }
 30→    return null;
 31→  }
 32→
 33→  function hitTestParts(modelPos) {
 34→    const tolerance = 6 / viewport.zoom;
 35→    const parts = project.parts.filter((p) => p.type !== 'dimension');
 36→
 37→    // Iterate in reverse for top-most first
 38→    for (let i = parts.length - 1; i >= 0; i--) {
 39→      const part = parts[i];
 40→      const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, activeView);
 41→
 42→      if (
 43→        modelPos.x >= svgX - tolerance &&
 44→        modelPos.x <= svgX + svgWidth + tolerance &&
 45→        modelPos.y >= svgY - tolerance &&
 46→        modelPos.y <= svgY + svgHeight + tolerance
 47→      ) {
 48→        return { id: part.id, type: 'part' };
 49→      }
 50→    }
 51→    return null;
 52→  }
 53→
 54→  return {
 55→    onMouseDown(modelPos, e, toolState) {
 56→      if (e.button !== 0) return;
 57→
 58→      // Try dimensions first (they render on top)
 59→      const dimHit = hitTestDimensions(modelPos);
 60→      if (dimHit) {
 61→        editorDispatch({ type: 'SELECT_OBJECT', id: dimHit.id, objectType: dimHit.type });
 62→        return;
 63→      }
 64→
 65→      const hit = hitTestParts(modelPos);
 66→      if (hit) {
 67→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
 68→        editorDispatch({
 69→          type: 'UPDATE_TOOL_STATE',
 70→          payload: { dragging: true, startPos: modelPos, dragPartId: hit.id },
 71→        });
 72→        return;
 73→      }
 74→
 75→      editorDispatch({ type: 'DESELECT' });
 76→    },
 77→
 78→    onMouseMove(modelPos, e, toolState, selectedId) {
 79→      if (!toolState.dragging || !toolState.startPos || !toolState.dragPartId) return;
 80→
 81→      const part = project.parts.find((p) => p.id === toolState.dragPartId);
 82→      if (!part || part.type === 'dimension') return;
 83→
 84→      const dx = modelPos.x - toolState.startPos.x;
 85→      const dy = modelPos.y - toolState.startPos.y;
 86→
 87→      if (Math.abs(dx) < 1 && Math.abs(dy) < 1) return;
 88→
 89→      // Compute position delta based on view
 90→      const pos = { ...part.position };
 91→      switch (activeView) {
 92→        case 'top':
 93→          pos.x += dx;
 94→          pos.y += dy;
 95→          break;
 96→        case 'front':
 97→          pos.x += dx;
 98→          pos.z -= dy;
 99→          break;
100→        case 'side':
101→          pos.y += dx;
102→          pos.z -= dy;
103→          break;
104→      }
105→
106→      // Snap final position if enabled
107→      if (snapEnabled) {
108→        const snapped = snapPoint(pos, SKETCH_GRID_MINOR);
109→        pos.x = snapped.x;
110→        pos.y = snapped.y;
111→      }
112→
113→      dispatch({
114→        type: 'PART_UPDATE',
115→        part: { id: toolState.dragPartId, position: pos },
116→      });
117→
118→      editorDispatch({
119→        type: 'UPDATE_TOOL_STATE',
120→        payload: { startPos: modelPos },
121→      });
122→    },
123→
124→    onMouseUp(modelPos, e, toolState) {
125→      if (toolState.dragging) {
126→        editorDispatch({
127→          type: 'UPDATE_TOOL_STATE',
128→          payload: { dragging: false, startPos: null, dragPartId: null },
129→        });
130→      }
131→    },
132→
133→    onKeyDown(e, toolState, selectedId) {
134→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
135→        dispatch({ type: 'PART_DELETE', partId: selectedId });
136→        editorDispatch({ type: 'DESELECT' });
137→      }
138→    },
139→
140→    getCursor(toolState) {
141→      if (toolState?.dragging) return 'grabbing';
142→      return 'default';
143→    },
144→  };
145→}
